from crewai import Agent
from difflib import SequenceMatcher

def detect_context_hallucination(agent_output, retrieved_context, threshold=0.3):
    context_text = ' '.join(retrieved_context)
    similarity = SequenceMatcher(None, agent_output, context_text).ratio()
    return {
        'hallucinated': similarity < threshold,
        'similarity_score': similarity,
        'issue': f'Agent hallucinated content (similarity: {similarity:.2f})' if similarity < threshold else None
    }

