class DelegationTracker:
    def __init__(self):
        self.delegations = {}

    def track_delegation(self, from_agent, to_agent, task):
        key = f'{from_agent.role}_{to_agent.role}'
        self.delegations[key] = self.delegations.get(key, 0) + 1

        if self.delegations[key] > 3:
            return {'loop_detected': True, 'count': self.delegations[key], 'issue': 'Delegation loop from RAG quality issues'}
