from crewai import Agent, Task
from rank_bm25 import BM25Okapi

class OptimizedRAGAgent(Agent):
    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.bm25 = None

    def setup_retrieval(self, documents):
        tokenized_docs = [doc.split(' ') for doc in documents]
        self.bm25 = BM25Okapi(tokenized_docs)

    def retrieve(self, query, k=5):
        if self.bm25:
            tokenized_query = query.split(' ')
            scores = self.bm25.get_scores(tokenized_query)
            top_indices = np.argsort(scores)[-k:][::-1]
            return [self.documents[i] for i in top_indices]
        return []

from crewai import Task

def create_faithful_task(description, context_chunks):
    context_str = '\n'.join([f"[CHUNK-{i}] {chunk}" for i, chunk in enumerate(context_chunks)])

    return Task(
        description=f"""
{description}

ONLY use information from these retrieved chunks:
{context_str}

ALWAYS cite chunk numbers in format [CHUNK-X] after each fact.
If answer not in chunks, say "Insufficient context provided".
        """.strip(),
        expected_output="Response with inline citations [CHUNK-X]"
    )
